INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000810, 'single', '90008', '森林面積的減少甚至消失可能導致哪些影響：A.水資源減少 B.減緩全球暖 化 C.加劇全球暖化 D.降低生物多樣性？', 'ACD,BCD,ABD,ABCD ', '0', '');
