INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000846, 'single', '90008', '小明拿到「垃圾強制分類」的宣導海報，標語寫著「分3 類，好OK」， 標語中的分3 類是指家戶日常生活中產生的垃圾可以區分哪三類？', '資源 垃圾、廚餘、事業廢棄物,資源垃圾、一般廢棄物、事業廢棄物,一般 廢棄物、事業廢棄物、放射性廢棄物,資源垃圾、廚餘、一般垃圾 ', '3', '');
