INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000858, 'single', '90008', '世紀之毒「戴奧辛」主要透過何者方式進入人體？', '透過觸摸,透過呼 吸,透過飲食,透過雨水 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000859, 'single', '90008', '臺灣地狹人稠，垃圾處理一直是不易解決的問題，下列何種是較佳的因應 對策？', '垃圾分類資源回收,蓋焚化廠,運至國外處理,向海爭地掩 埋 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000860, 'single', '90008', '購買下列哪一種商品對環境比較友善？', '用過即丟的商品,一次性的產 品,材質可以回收的商品,過度包裝的商品 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000861, 'single', '90008', '下列何項法規的立法目的為預防及減輕開發行為對環境造成不良影響，藉 以達成環境保護之目的？', '公害糾紛處理法,環境影響評估法,環境基 本法,環境教育法 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000862, 'single', '90008', '下列何種開發行為若對環境有不良影響之虞者，應實施環境影響評估：A. 開發科學園區；B.新建捷運工程；C.採礦。', 'AB,BC,AC,ABC ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000863, 'single', '90008', '主管機關審查環境影響說明書或評估書，如認為已足以判斷未對環境有重 大影響之虞，作成之審查結論可能為下列何者？', '通過環境影響評估審查,應繼續進行第二階段環境影響評估,認定不應開發,補充修正資料再 審 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000864, 'single', '90008', '依環境影響評估法規定，對環境有重大影響之虞的開發行為應繼續進行第 二階段環境影響評估，下列何者不是上述對環境有重大影響之虞或應進行 第二階段環境影響評估的決定方式？', '明訂開發行為及規模,環評委員 會審查認定,自願進行,有民眾或團體抗爭 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000865, 'single', '90008', '依環境教育法，環境教育之戶外學習應選擇何地點辦理？', '遊樂園,環 境教育設施或場所,森林遊樂區,海洋世界 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000866, 'single', '90008', '依環境影響評估法規定，環境影響評估審查委員會審查環境影響說明書， 認定下列對環境有重大影響之虞者，應繼續進行第二階段環境影響評估， 下列何者非屬對環境有重大影響之虞者？', '對保育類動植物之棲息生存有 顯著不利之影響,對國家經濟有顯著不利之影響,對國民健康有顯著不 利之影響,對其他國家之環境有顯著不利之影響 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000867, 'single', '90008', '依環境影響評估法規定，第二階段環境影響評估，目的事業主管機關應舉 行下列何種會議？', '說明會,聽證會,辯論會,公聽會 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000868, 'single', '90008', '開發單位申請變更環境影響說明書、評估書內容或審查結論，符合下列哪 一情形，得檢附變更內容對照表辦理？', '既有設備提昇產能而污染總量增 加在百分之十以下,降低環境保護設施處理等級或效率,環境監測計畫 變更,開發行為規模增加未超過百分之五 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000869, 'single', '90008', '開發單位變更原申請內容有下列哪一情形，無須就申請變更部分，重新辦 理環境影響評估？', '不降低環保設施之處理等級或效率,規模擴增百分 之十以上,對環境品質之維護有不利影響,土地使用之變更涉及原規劃 之保護區 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000870, 'single', '90008', '工廠或交通工具排放空氣污染物之檢查，下列何者錯誤？', '依中央主管機 關規定之方法使用儀器進行檢查,檢查人員以嗅覺進行氨氣濃度之判定,檢查人員以嗅覺進行異味濃度之判定,檢查人員以肉眼進行粒狀污染物 排放濃度之判定 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000871, 'single', '90008', '下列對於空氣污染物排放標準之敘述，何者正確：A.排放標準由中央主管 機關訂定；B.所有行業之排放標準皆相同？', '僅A,僅B,AB 皆正確,AB 皆錯誤 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000872, 'single', '90008', '下列對於細懸浮微粒(PM 2 .5)之敘述何者正確：A.空氣品質測站中自動監測 儀所測得之數值若高於空氣品質標準，即判定為不符合空氣品質標準；B. 濃度監測之標準方法為中央主管機關公告之手動檢測方法；C.空氣品質標 準之年平均值為15μg/m 3？', '僅AB,僅BC,僅AC,ABC 皆正 確 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000873, 'single', '90008', '機車為空氣污染物之主要排放來源之一，下列何者可降低空氣污染物之排 放量：A.將四行程機車全面汰換成二行程機車；B.推廣電動機車；C.降低 汽油中之硫含量？', '僅AB,僅BC,僅AC,ABC 皆正確 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000874, 'single', '90008', '公眾聚集量大且滯留時間長之場所，經公告應設置自動監測設施，其應量 測之室內空氣污染物項目為何？', '二氧化碳,一氧化碳,臭氧,甲 醛 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000875, 'single', '90008', '空氣污染源依排放特性分為固定污染源及移動污染源，下列何者屬於移動 污染源？', '焚化廠,石化廠,機車,煉鋼廠 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000876, 'single', '90008', '我國汽機車移動污染源空氣污染防制費的徵收機制為何？', '依牌照徵收,隨水費徵收,隨油品銷售徵收,購車時徵收 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000877, 'single', '90008', '細懸浮微粒(PM 2. 5)除了來自於污染源直接排放外，亦可能經由下列哪一種 反應產生？', '光合作用,酸鹼中和,厭氧作用,光化學反應 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000878, 'single', '90008', '我國固定污染源空氣污染防制費以何種方式徵收？', '依營業額徵收,隨 使用原料徵收,按工廠面積徵收,依排放污染物之種類及數量徵收 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000879, 'single', '90008', '在不妨害水體正常用途情況下，水體所能涵容污染物之量稱為', '涵容能力,放流能力,運轉能力,消化能力 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000880, 'single', '90008', '水污染防治法中所稱地面水體不包括下列何者？', '河川,海洋,灌溉渠 道,地下水 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000881, 'single', '90008', '下列何者不是主管機關設置水質監測站採樣的項目？', '水溫,氫離子濃 度指數,溶氧量,顏色 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000882, 'single', '90008', '事業、污水下水道系統及建築物污水處理設施之廢（污）水處理，其產生 之污泥，依規定應作何處理？', '應妥善處理，不得任意放置或棄置,可 作為農業肥料,可作為建築土方,得交由清潔隊處理 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000883, 'single', '90008', '依水污染防治法，事業排放廢(污)水於地面水體者，應符合下列哪一標準 之規定？', '下水水質標準,放流水標準,水體分類水質標準,土壤處理 標準 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000884, 'single', '90008', '放流水標準，依水污染防治法應由何機關定之：A.中央主管機關；B.中央 主管機關會同相關目的事業主管機關；C.中央主管機關會商相關目的事業 主管機關？', '僅A,僅B,僅C,ABC ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000885, 'single', '90008', '對於噪音之量測，下列何者錯誤？', '可於下雨時測量,風速大於每秒5 公尺時不可量測,聲音感應器應置於離地面或樓板延伸線1.2 至1.5 公尺 之間,測量低頻噪音時，僅限於室內地點測量，非於戶外量測 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000886, 'single', '90008', '下列對於噪音管制法之規定何者敘述錯誤？', '噪音指超過管制標準之聲音,環保局得視噪音狀況劃定公告噪音管制區,人民得向主管機關檢舉使用 中機動車輛噪音妨害安寧情形,使用經校正合格之噪音計皆可執行噪音管 制法規定之檢驗測定 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000887, 'single', '90008', '製造非持續性但卻妨害安寧之聲音者，由下列何單位依法進行處理？', '警 察局,環保局,社會局,消防局 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000888, 'single', '90008', '廢棄物、剩餘土石方清除機具應隨車持有證明文件且應載明廢棄物、剩餘 土石方之：A 產生源；B 處理地點；C 清除公司', '僅AB,僅BC,僅AC,ABC 皆是 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000889, 'single', '90008', '從事廢棄物清除、處理業務者，應向直轄市、縣（市）主管機關或中央主 管機關委託之機關取得何種文件後，始得受託清除、處理廢棄物業務？', '公民營廢棄物清除處理機構許可文件,運輸車輛駕駛證明,運輸車輛購 買證明,公司財務證明 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000890, 'single', '90008', '在何種情形下，禁止輸入事業廢棄物：A.對國內廢棄物處理有妨礙；B.可 直接固化處理、掩埋、焚化或海拋；C.於國內無法妥善清理？', '僅A,僅B,僅C,ABC ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000891, 'single', '90008', '毒性化學物質因洩漏、化學反應或其他突發事故而污染運作場所周界外之 環境，運作人應立即採取緊急防治措施，並至遲於多久時間內，報知直轄 市、縣（市）主管機關？', '1 小時,2 小時,4 小時,30 分鐘 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000892, 'single', '90008', '下列何種物質或物品，受毒性及關注化學物質管理法之管制？', '製造醫藥 之靈丹,製造農藥之蓋普丹,含汞之日光燈,使用青石綿製造石綿 瓦 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000893, 'single', '90008', '下列何行為不是土壤及地下水污染整治法所指污染行為人之作為？', '洩漏 或棄置污染物,非法排放或灌注污染物,仲介或容許洩漏、棄置、非法 排放或灌注污染物,依法令規定清理污染物 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000894, 'single', '90008', '依土壤及地下水污染整治法規定，進行土壤、底泥及地下水污染調查、整 治及提供、檢具土壤及地下水污染檢測資料時，其土壤、底泥及地下水污 染物檢驗測定，應委託何單位辦理？', '經中央主管機關許可之檢測機構,大專院校,政府機關,自行檢驗 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000895, 'single', '90008', '為解決環境保護與經濟發展的衝突與矛盾，1992 年聯合國環境發展大會 （UN Conference on Environment and Development, UNCED）制定通過：', '日內瓦公約,蒙特婁公約,21 世紀議程,京都議定書 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000896, 'single', '90008', '一般而言，下列那一個防治策略是屬經濟誘因策略？', '可轉換排放許可交 易,許可證制度,放流水標準,環境品質標準 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000897, 'single', '90008', '對溫室氣體管制之「無悔政策」係指：', '減輕溫室氣體效應之同時，仍可 獲致社會效益,全世界各國同時進行溫室氣體減量,各類溫室氣體均有 相同之減量邊際成本,持續研究溫室氣體對全球氣候變遷之科學證 據 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000898, 'single', '90008', '一般家庭垃圾在進行衛生掩埋後，會經由細菌的分解而產生甲烷氣，請問 甲烷氣對大氣危機中哪一些效應具有影響力？', '臭氧層破壞,酸雨,溫 室效應,煙霧（smog）效應 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000899, 'single', '90008', '下列國際環保公約，何者限制各國進行野生動植物交易，以保護瀕臨絕種 的野生動植物？', '華盛頓公約,巴塞爾公約,蒙特婁議定書,氣候變化 綱要公約 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `subject`, `question`, `options`, `answer`, `image`) VALUES (9000900, 'single', '90008', '因人類活動導致「哪些營養物」過量排入海洋，造成沿海赤潮頻繁發生， 破壞了紅樹林、珊瑚礁、海草，亦使魚蝦銳減，漁業損失慘重？', '碳及磷,氮及磷,氮及氯,氯及鎂 ', '1', '');